const StageExecutor = require('../../../src/core/StageExecutor');
const { expect } = require('chai');

describe('StageExecutor (Unit)', () => {
  beforeEach(() => {
    // Reset processors for test isolation
    StageExecutor.registerStageProcessor('TestStage', () => {});
  });

  it('should register and execute processors for a stage', async () => {
    const calls = [];
    const processor1 = ctx => calls.push('processor1');
    const processor2 = ctx => calls.push('processor2');

    StageExecutor.registerStageProcessor('TestStage', processor1);
    StageExecutor.registerStageProcessor('TestStage', processor2);

    await StageExecutor.executeStage('TestStage', {});

    expect(calls).to.deep.equal(['processor1', 'processor2']);
  });

  it('should return empty array for unknown stage', () => {
    const result = StageExecutor.getStageProcessors('UnknownStage');
    expect(result).to.deep.equal([]);
  });
});